import{c as a,Z as r,Q as i,j as l,g as t,n,o as s,m as h}from"./chunks/framework.qjzPVSkb.js";const C=JSON.parse('{"title":"思维链 (CoT)","description":"Chain-of-Thought——引导模型逐步推理再给出答案，显著提升数学和逻辑推理能力","frontmatter":{"title":"思维链 (CoT)","description":"Chain-of-Thought——引导模型逐步推理再给出答案，显著提升数学和逻辑推理能力","difficulty":"advanced"},"headers":[],"relativePath":"terms/cot.md","filePath":"terms/cot.md"}'),d={name:"terms/cot.md"};function g(u,e,c,p,f,m){const o=r("DifficultyBadge");return i(),l("div",null,[e[0]||(e[0]=t("h1",{id:"思维链-cot",tabindex:"-1"},[n("思维链 (CoT) "),t("a",{class:"header-anchor",href:"#思维链-cot","aria-label":'Permalink to "思维链 (CoT)"'},"​")],-1)),s(o,{level:"advanced"}),e[1]||(e[1]=h('<h2 id="一句话解释" tabindex="-1">一句话解释 <a class="header-anchor" href="#一句话解释" aria-label="Permalink to &quot;一句话解释&quot;">​</a></h2><p>思维链（Chain-of-Thought, CoT）是一种<strong>引导语言模型在给出最终答案前，先输出中间推理步骤</strong>的技术。通过&quot;Let&#39;s think step by step&quot;这样的提示，让模型将复杂问题拆解为一系列逻辑步骤，从而在数学、逻辑推理、多步决策等任务中显著提升准确率。</p><h2 id="通俗类比" tabindex="-1">通俗类比 <a class="header-anchor" href="#通俗类比" aria-label="Permalink to &quot;通俗类比&quot;">​</a></h2><p>解一道复杂的数学题，如果你直接脱口而出答案，很可能出错。但如果你在草稿纸上一步步写下计算过程——先读题、找关键数据、列方程、代入、求解——正确率就大大提高。CoT 就是让模型也在&quot;草稿纸&quot;上写推理过程：不是直接跳到答案，而是先输出&quot;题目给出的条件是……我需要先算……然后是……所以答案是……&quot;。这个过程不仅提升了正确率，还让模型的思考过程变得可检查和可信任。</p><h2 id="技术定义" tabindex="-1">技术定义 <a class="header-anchor" href="#技术定义" aria-label="Permalink to &quot;技术定义&quot;">​</a></h2><p>CoT 有多种实现方式：</p><ol><li><strong>Few-Shot CoT</strong>：在 Prompt 中给出几个&quot;问题 → 分步推理 → 答案&quot;的示例，模型学习这种格式后，遇到新问题也会模仿着逐步推理。这是原始论文（Wei et al., 2022）提出的经典方式</li><li><strong>Zero-Shot CoT</strong>：不需要任何示例，只需添加一句魔法提示词&quot;Let&#39;s think step by step&quot;，模型就会自发地开始分步推理。这种方式更简洁，在大多数场景下效果与 Few-Shot 相当</li><li><strong>Auto-CoT</strong>：自动为 Few-Shot CoT 生成示例，减少人工构造示例的工作量</li></ol><p>CoT 发挥作用的关键前提是<strong>模型规模足够大</strong>（通常需要 100B+ 参数），小模型使用 CoT 提升有限甚至可能下降。这也是为什么 CoT 被认为是 LLM 的一种<strong>涌现能力（Emergent Ability）</strong>。</p><p>CoT 的进阶变体：</p><ul><li><strong>Self-Consistency</strong>：多次独立运行 CoT，取出现频率最高的答案，进一步提升稳定性</li><li><strong>Tree of Thoughts（ToT）</strong>：不只一条推理链，而是像下棋一样探索多条推理路径</li><li><strong>Chain-of-Thought with Verification</strong>：推理完成后，让模型自行检查验证推理过程</li></ul><h2 id="关联术语" tabindex="-1">关联术语 <a class="header-anchor" href="#关联术语" aria-label="Permalink to &quot;关联术语&quot;">​</a></h2><ul><li><a href="/ai-knowledge/terms/prompt.html">Prompt</a> —— CoT 是一种特定形式的 Prompt 技巧</li><li><a href="/ai-knowledge/terms/agent.html">Agent</a> —— Agent 的任务规划本质就是内部使用 CoT 进行思考</li><li><a href="/ai-knowledge/terms/llm.html">大语言模型 (LLM)</a> —— CoT 效果与模型规模强相关</li></ul><h2 id="快速记忆" tabindex="-1">快速记忆 <a class="header-anchor" href="#快速记忆" aria-label="Permalink to &quot;快速记忆&quot;">​</a></h2><p>CoT = 显式写出推理过程。不给 AI 直接问答案的机会，逼它一步一步想。记住：&#39;Let&#39;s think step by step&#39; 是最值的七个词。</p><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li>原始论文：<a href="https://arxiv.org/abs/2201.11903" target="_blank" rel="noreferrer">Chain-of-Thought Prompting Elicits Reasoning in Large Language Models</a>（Wei et al., 2022）</li><li>Zero-Shot CoT：<a href="https://arxiv.org/abs/2205.11916" target="_blank" rel="noreferrer">Large Language Models are Zero-Shot Reasoners</a></li><li><a href="/ai-knowledge/dev/reasoning-models.html">推理模型使用</a> — o1/DeepSeek-R1 的正确打开方式</li></ul>',16))])}const b=a(d,[["render",g]]);export{C as __pageData,b as default};
